      remove: span.has-text-red
    details:
      selector: a[href^="details.php?id="]
      attribute: href
    download:
      selector: a[href^="download.php?torrent="]
      attribute: href
    poster:
      selector: img[src^="/img.php?"]
      attribute: src
    files:
      selector: a[href^="filelist.php?id="]
    date_day:
      # auto adjusted by site account profile
      # Yesterday 6:00 AM
      selector: td:nth-last-child(2) > div:contains("day")
      optional: true
      filters:
        - name: fuzzytime
    date_year:
      # auto adjusted by site account profile
      # Aug 6 2021 7:25 PM
      selector: td:nth-last-child(2) > div:not(:contains("day"))
      optional: true
      filters:
        - name: dateparse
          args: "MMM d yyyyh:mm tt"
    date:
      text: "{{ if or .Result.date_day .Result.date_year }}{{ or .Result.date_day .Result.date_year }}{{ else }}now{{ end }}"
    size:
      selector: td:nth-last-child(4) div[title^="Size"]
    grabs:
      selector: a[href^="snatches.php?id="]
    seeders:
      selector: a[title$="Seeders"]
      optional: true
      default: 0
    leechers:
      selector: a[title$="Leechers"]
      optional: true
      default: 0
    downloadvolumefactor:
      case:
        tr.freeleech_color: 0
        "*": 1
    uploadvolumefactor:
      text: 1
    minimumseedtime:
      # 14 days (as seconds = 14 x 24 x 60 x 60)
      text: 1209600
