        - name: re_replace
          args: ["^\\[(\\d+(?:[\\s-]+\\d+)*)\\](?!\\s*\\[م)", "S01E$1"]
        - name: re_replace
          args: ["E(\\d+)[\\s-]+(\\d+)", "E$1-E$2"]
        - name: re_replace
          args: ["\\[\\s*\\]", ""]
        - name: re_replace
          args: ["(?<=\\S)(\\[)", " $1"]
        - name: re_replace
          args: ["S(\\d)(?=E)", "S0$1"]
        - name: re_replace
          args: ["E(\\d)(?=\\D)", "E0$1"]
        - name: re_replace
          args: ["\\s{2,}", " "]
        - name: trim
    details:
      selector: a[href*="/details.php?id="]
      attribute: href
    download:
      selector: a[href*="/download.php?id="]
      attribute: href
    date:
      selector: td:nth-child(2) > div:nth-child(3)
      filters:
        - name: regexp
          args: "(\\d{2}-\\d{2}-\\d{4} \\d{2}:\\d{2})"
        - name: dateparse
          args: "dd-MM-yyyy HH:mm"
    size:
      selector: td:nth-child(5)
    grabs:
      selector: td:nth-child(6)
    seeders:
      selector: td:nth-child(7)
    leechers:
      selector: td:nth-child(8)
    poster:
      selector: div.tooltip-content > img[src*="/torrents/"]
      attribute: src
    downloadvolumefactor:
      case:
        img[src$="torrent_flags/freedownload.gif"]: 0
        img[src$="torrent_flags/silverdownload.gif"]: 0.5
        "*": 1
    uploadvolumefactor:
      case:
        img[src$="torrent_flags/x2.gif"]: 2
        "*": 1
    minimumratio:
      text: 1.0
    minimumseedtime:
      # 3 days (as seconds = 3 x 24 x 60 x 60)
      text: 259200
